# Initiate a reservation exchange via REST API
# (Portal is the recommended path; CLI support is limited)
az rest --method post \
  --url 'https://management.azure.com/providers/Microsoft.Capacity/exchange?api-version=2022-11-01' \
  --body '{
    "properties": {
      "reservationsToExchange": [
        {
          "reservationId": "/providers/Microsoft.Capacity/reservationOrders/<orderId>/reservations/<resId>",
          "quantity": 1
        }
      ],
      "reservationsToPurchase": [
        {
          "sku": { "name": "Standard_D4s_v3" },
          "location": "westus2",
          "reservedResourceType": "VirtualMachines",
          "reservedResourceProperties": { "instanceFlexibility": "On" },
          "term": "P1Y",
          "quantity": 1,
          "billingScope": "/subscriptions/<sub-id>",
          "billingPlan": "Upfront",
          "appliedScopeType": "Single",
          "appliedScopes": ["/subscriptions/<sub-id>"]
        }
      ]
    }
  }'

import datetime
from azure.identity import DefaultAzureCredential
from azure.mgmt.consumption import ConsumptionManagementClient

credential = DefaultAzureCredential()
client = ConsumptionManagementClient(credential, "<subscription-id>")

end = datetime.date.today()
start = end - datetime.timedelta(days=30)

summaries = client.reservations_summaries.list(
    reservation_order_id="<order-id>",
    reservation_id="<reservation-id>",
    grain="daily",
    filter=f"properties/usageDate ge {start} AND properties/usageDate le {end}"
)

underused = []
for s in summaries:
    util = s.avg_utilization_percentage or 0
    if util < 85:
        underused.append({
            "date": str(s.usage_date.date()),
            "utilization_pct": round(util, 1),
            "reserved_hours": s.reserved_hours,
            "used_hours": s.used_hours,
        })

if underused:
    print(f"WARNING: {len(underused)} days below 85% utilization:")
    for day in underused[:5]:
        print(f"  {day['date']}: {day['utilization_pct']}% ({day['used_hours']:.1f}/{day['reserved_hours']:.1f} hrs)")
else:
    print("Reservation utilization healthy (>= 85% every day).")

from azure.identity import DefaultAzureCredential
from azure.mgmt.advisor import AdvisorManagementClient

credential = DefaultAzureCredential()
client = AdvisorManagementClient(credential, "<subscription-id>")

recommendations = client.recommendations.list(
    filter="Category eq 'Cost'"
)

print("Reservation purchase recommendations from Advisor:")
for rec in recommendations:
    sol = rec.short_description.solution if rec.short_description else ""
    if "reservation" in sol.lower():
        print(f"  [{rec.impact}] {sol}")
        ext = rec.extended_properties or {}
        if "annualSavingsAmount" in ext:
            print(f"    Estimated annual savings: ${ext['annualSavingsAmount']}")
